using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// Breaking change 1 – ValidateOnBuild / ValidateScopes (enabled by default in
// dev in .NET 9).  A singleton must not capture a scoped service.  Inject the
// factory instead so a fresh scope is created on each use.
builder.Services.AddSingleton<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IServiceScopeFactory>()));

// Breaking change 2 – HttpClientFactory now uses SocketsHttpHandler by default.
// Casting PrimaryHandler to HttpClientHandler throws InvalidCastException.
// Use ConfigurePrimaryHttpMessageHandler to set an explicit handler.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() =>
        new SocketsHttpHandler { UseCookies = false });

// Breaking change 3 – Forwarded-headers middleware now ignores X-Forwarded-*
// headers from proxies not in KnownProxies / KnownNetworks.
// Add your reverse-proxy address(es) here.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(System.Net.IPAddress.Parse("127.0.0.1"));
});

// Breaking change 4 – HttpClientFactory Trace-level logs now redact all header
// values by default.  Allowlist the non-sensitive headers you need for debugging.
builder.Services.AddHttpClient()
    .RedactLoggedHeaders(h =>
        h != "X-Request-Id" && h != "X-Correlation-Id" && h != "Accept");

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

// Stub types – replace with your real implementations
public interface IUserService { }
public class UserService : IUserService { }
public interface ICacheService { }
public class CacheService : ICacheService
{
    public CacheService(IServiceScopeFactory scopeFactory) { }
}

